#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[100005];
        scanf("%s", s);
        int x, y;
        scanf("%d %d", &x, &y);
        int n = strlen(s);
        char res[100005] = {0};
        int idx = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == 'a') {
                int cnt = 0;
                for (int j = i - 1; j >= 0 && cnt < x; j--) {
                    if (res[j] == 'a') cnt++;
                }
                if (cnt == x) {
                    res[idx++] = '*';
                }
            } else {
                int cnt = 0;
                for (int j = i - 1; j >= 0 && cnt < y; j--) {
                    if (res[j] == 'b') cnt++;
                }
                if (cnt == y) {
                    res[idx++] = '*';
                }
            }
            res[idx++] = s[i];
        }
        res[idx] = '\0';
        printf("%s\n", res);
    }
    return 0;
}

