import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String s = sc.next();
            int x = sc.nextInt();
            int y = sc.nextInt();
            int n = s.length();
            StringBuilder res = new StringBuilder();
            for (int i = 0; i < n; i++) {
                if (s.charAt(i) == 'a') {
                    int cnt = 0;
                    for (int j = res.length() - 1; j >= 0 && cnt < x; j--) {
                        if (res.charAt(j) == 'a') cnt++;
                    }
                    if (cnt == x) {
                        res.append('*');
                    }
                } else {
                    int cnt = 0;
                    for (int j = res.length() - 1; j >= 0 && cnt < y; j--) {
                        if (res.charAt(j) == 'b') cnt++;
                    }
                    if (cnt == y) {
                        res.append('*');
                    }
                }
                res.append(s.charAt(i));
            }
            System.out.println(res.toString());
        }
    }
}

